class Solution:
    def waysToBuyPensPencils(self, total: int, cost1: int, cost2: int) -> int:
        if cost1 > total or cost2 > total:
            return 1
        dp = [[0] * (total // cost1 + 1) for _ in range(total // cost2 + 1)]
        for i in range(total // cost2 + 1):
            dp[i][0] = 1
        for i in range(total // cost2 + 1):
            for j in range(total // cost1 + 1):
                if i * cost2 + j * cost1 <= total:
                    dp[i][j] = dp[i][j-1] + dp[i-1][j]
                else:
                    dp[i][j] = dp[i][j-1]
        return dp[-1][-1]
